/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(AgreementConfirmRunForm, OKButton), FormControlEventType::Clicked)]
public static void OKButton_OnClicked(FormControl sender, FormControlEventArgs e)
{
    FormRun                     formrun;
    AgreementProformaConfirm    agreementConfirm;
    str                         comments;

    formrun          = sender.formRun();
    agreementConfirm = formrun.args().caller();
    comments         = formrun.design().controlName("Amendment").valueStr();
    if (comments == "")
    {
        throw error("@ETG_Labels:AmendmentMandatoryMsg");
    }
}
